    void *res= priobj->elem;
    free(priobj);
    return res;
  }
}

void priPut(PriQueue *q, void *elem, double pri) {
  PriObj *priobj= malloc(sizeof(PriObj));
  priobj->pri= pri;
  priobj->elem= elem;
  fullPriPut(q, priobj);
}

int priDel(PriQueue *q, void *elem) {
  int k= 0;
  PriObj *priobj;
  while (k<=q->size) {
    priobj= q->ar[k];
    if (priobj->elem==elem)
      break;
    k++;
  }
  if (k>q->size)
    return 1;

  q->ar[k]= q->ar[q->size];
  q->size--;
  if (k<q->size)
    shiftDown(q, k);
  free(priobj);
  return 0;
}

