  sigact.sa_mask= nth_sigsetCritical;
  sigact.sa_sigaction= nth_Usr1Handler;

  if (sigaction(SIGUSR1, &sigact, NULL)!=0) {
    perror("sigaction");
    nFatalError("nth_systemInit", "Cannot continue\n");
  }

