#include <nthread-impl.h>
#include "subasta.h"

// =============================================================
// Implemente a partir de aca el tipo Subasta, puede agregar
// funciones, estructuras o variables que considere necesarias
// =============================================================

// Structure representing a bidder waiting for the auction
typedef struct oferente {
  nThread th;           // Thread of the bidder
  nSubasta s;           // The auction this bidder belongs to
  double precio;        // Offered price
  int resultado;        // -1: waiting, 0: lost (FALSE), 1: won (TRUE)
} Oferente;

struct subasta {
  int n;                // Number of items being auctioned
  int size;             // Number of bidders currently in the pool
  int cerrado;          // 1 when adjudicar has been called
  double total;         // Total amount collected (sum of winning bids)
  int noVendidas;       // Unsold units
  PriQueue *pq;         // Priority queue of Oferente* (min-heap by price)
};

// Forward declaration
static void kickLowest(nSubasta s);

// Wake-up function for timeout: called when the timer fires for a waiting bidder
static void wakeUpSubasta(nThread th) {
  Oferente *of = (Oferente *)th->ptr;
  if (of != NULL && of->resultado == -1) {
    // Timeout expired, this bidder loses
    of->resultado = 0;  // FALSE
    // Remove from the priority queue
    nSubasta s = of->s;
    if (!s->cerrado) {
      priDel(s->pq, of);
      s->size--;
    }
  }
  // nth_wakeThreads will call setReady(th) after this function returns
}

nSubasta nNuevaSubasta(int n) {
  nSubasta s = (nSubasta)malloc(sizeof(struct subasta));
  if (s == NULL) return NULL;
  s->n = n;
  s->size = 0;
  s->cerrado = 0;
  s->total = 0;
  s->noVendidas = 0;
  s->pq = makePriQueue();
  return s;
}

void nDestruirSubasta(nSubasta s) {
  START_CRITICAL

  // Destroy the priority queue (should be empty at this point)
  destroyPriQueue(s->pq);
  free(s);

  END_CRITICAL
}

// Remove the lowest bidder from the pool (kicks them out with FALSE)
// Requires: s->size > s->n
static void kickLowest(nSubasta s) {
  // The priority queue is a max-heap, but we store with negative price
  // so the "highest" (most negative) is actually the lowest price.
  // priPeek returns the element with highest priority.
  // Since we use -precio as priority, the element with the most
  // negative priority (lowest price) is at the top.

  Oferente *of = (Oferente *)priGet(s->pq);
  s->size--;

  of->resultado = 0;  // FALSE (lost)
  nThread th = of->th;

  // If the thread had a timer pending, cancel it
  if (th->status == WAIT_SUBASTA_TIMEOUT) {
    nth_cancelThread(th);
  }

  // Wake the thread up
  setReady(th);
}

int nOfrecer(nSubasta s, double oferta, int timeout) {
  Oferente *of = NULL;
  int result = FALSE;

  START_CRITICAL

  // Create the bidder descriptor
  of = (Oferente *)malloc(sizeof(Oferente));
  of->th = nSelf();
  of->s = s;
  of->precio = oferta;
  of->resultado = -1;  // waiting

  // Store reference in the thread's ptr field for wakeUpSubasta to find
  nThread thisTh = nSelf();
  thisTh->ptr = of;

  // Add to the priority queue with negative price (for min-heap behavior)
  priPut(s->pq, of, -oferta);
  s->size++;

  // If the pool exceeds n items, kick out the lowest bidder
  if (s->size > s->n) {
    kickLowest(s);
  }

  // Check if we were kicked out immediately
  if (of->resultado != -1) {
    // Kicked out, we already got FALSE
    result = of->resultado;
    thisTh->ptr = NULL;
    free(of);
    END_CRITICAL
    return result;
  }

  // We are waiting. If the auction is already closed, handle it.
  // (This can happen if adjudicar was called while we were being added)
  if (s->cerrado) {
    // The auction closed while we were adding ourselves
    // The closing process should have processed all bidders
    // But we were added after closure, so we need to handle this edge case
    // Re-check: if pool has <= n bidders, we win; otherwise we lose
    // Actually, since adjudicar has been called, we are processed now

    // Remove ourselves and let adjudicar logic handle it
    // But adjudicar already finished, so we need to determine now

    // Simply: we're in the pool. Evaluate like adjudicar would.
    // For simplicity: since adjudicar was called, this is an error condition.
    // We'll just return FALSE as we can't be adjudicated.
    priDel(s->pq, of);
    s->size--;
    result = FALSE;
    thisTh->ptr = NULL;
    free(of);
    END_CRITICAL
    return result;
  }

  // Suspend and wait for adjudicar or timeout
  if (timeout < 0) {
    // Infinite wait
    suspend(WAIT_SUBASTA);
  } else {
    // Wait with timeout (timeout is in milliseconds)
    suspend(WAIT_SUBASTA_TIMEOUT);
    nth_programTimer((long long)timeout * 1000000LL, wakeUpSubasta);
  }

  schedule();

  // We woke up: either adjudicar was called, or timeout fired, or we were kicked
  result = of->resultado;
  if (result == -1) {
    // Should not happen, but handle gracefully
    result = FALSE;
  }

  thisTh->ptr = NULL;
  free(of);

  END_CRITICAL
  return result;
}

double nAdjudicar(nSubasta s, int *punid) {
  START_CRITICAL

  s->cerrado = 1;
  s->total = 0;

  // Collect all bidders from the priority queue
  int nBidders = s->size;
  Oferente **arr = NULL;

  if (nBidders > 0) {
    arr = (Oferente **)malloc(nBidders * sizeof(Oferente *));
    for (int i = 0; i < nBidders; i++) {
      PriObj *priobj = (PriObj *)fullPriPeek(s->pq);
      if (priobj == NULL) break;
      arr[i] = (Oferente *)priobj->elem;
      fullPriGet(s->pq);  // Remove from heap
    }
    s->size = 0;
  }

  // Determine winners: top n prices win, rest lose
  int winners = nBidders < s->n ? nBidders : s->n;

  // Sort bidders by price descending (simple bubble sort for simplicity)
  // arr[0..nBidders-1] contains all bidders
  for (int i = 0; i < nBidders - 1; i++) {
    for (int j = 0; j < nBidders - i - 1; j++) {
      if (arr[j]->precio < arr[j + 1]->precio) {
        Oferente *tmp = arr[j];
        arr[j] = arr[j + 1];
        arr[j + 1] = tmp;
      }
    }
  }

  // First winners (top n)
  for (int i = 0; i < winners; i++) {
    arr[i]->resultado = 1;  // TRUE (won)
    s->total += arr[i]->precio;

    // Cancel any pending timer
    if (arr[i]->th->status == WAIT_SUBASTA_TIMEOUT) {
      nth_cancelThread(arr[i]->th);
    }
    setReady(arr[i]->th);
  }

  // Then losers (the rest)
  for (int i = winners; i < nBidders; i++) {
    arr[i]->resultado = 0;  // FALSE (lost)

    // Cancel any pending timer
    if (arr[i]->th->status == WAIT_SUBASTA_TIMEOUT) {
      nth_cancelThread(arr[i]->th);
    }
    setReady(arr[i]->th);
  }

  // Unsold units
