double nAdjudicar(nSubasta s, int *punid) {
  START_CRITICAL

  s->cerrado = 1;
  s->total = 0;

  // Collect all bidders from the priority queue
  // priGet extracts in ascending price order (min-heap: lowest price first)
  int nBidders = s->size;
  Oferente **arr = NULL;

  if (nBidders > 0) {
    arr = (Oferente **)malloc(nBidders * sizeof(Oferente *));
    for (int i = 0; i < nBidders; i++) {
      arr[i] = (Oferente *)priGet(s->pq);
    }
    s->size = 0;
  }

  // Reverse array so we have descending price order
  // (priGet gives ascending: lowest price first)
  for (int i = 0; i < nBidders / 2; i++) {
    Oferente *tmp = arr[i];
    arr[i] = arr[nBidders - 1 - i];
    arr[nBidders - 1 - i] = tmp;
  }

  // Determine winners: top n prices win, rest lose
  int winners = nBidders < s->n ? nBidders : s->n;

  // First winners (top n)
  for (int i = 0; i < winners; i++) {
    arr[i]->resultado = 1;  // TRUE (won)
    s->total += arr[i]->precio;

    // Cancel any pending timer and wake up thread
    if (arr[i]->th->status == WAIT_SUBASTA_TIMEOUT) {
      nth_cancelThread(arr[i]->th);
    }
    setReady(arr[i]->th);
  }

  // Then losers (the rest)
  for (int i = winners; i < nBidders; i++) {
    arr[i]->resultado = 0;  // FALSE (lost)

    // Cancel any pending timer and wake up thread
    if (arr[i]->th->status == WAIT_SUBASTA_TIMEOUT) {
      nth_cancelThread(arr[i]->th);
    }
    setReady(arr[i]->th);
  }

  // Unsold units
  s->noVendidas = s->n - winners;

  if (arr != NULL) free(arr);

  if (punid != NULL) *punid = s->noVendidas;

  schedule();

  END_CRITICAL
  return s->total;
}

